const rows = $input.all();
const TELEGRAM_BOT_TOKEN = 'REPLACE_WITH_BOT_TOKEN';

let offsetValue = 0;
if (rows.length > 0 && rows[0].json.offset_value) {
  const raw = rows[0].json.offset_value;
  const match = raw.toString().match(/(\d+)/);
  offsetValue = match ? parseInt(match[1]) : 0;
}

const url = `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getUpdates?offset=${offsetValue}&limit=20`;

return [{ json: { url, current_offset: offsetValue } }];

const crypto = require('crypto');

const input = $input.first().json;
const updates = input.result || [];

if (!updates.length) {
  return [{ json: { rows: [], max_update_id: null, count: 0 } }];
}

const rows = [];
let maxUpdateId = 0;

for (const update of updates) {
  const updateId = update.update_id;
  if (updateId > maxUpdateId) maxUpdateId = updateId;

  const msg = update.message || update.channel_post;
  if (!msg) continue;

  const text = msg.text || msg.caption || '';
  if (!text || text.length < 20) continue;

  let imageUrl = null;
  if (msg.photo && msg.photo.length > 0) {
    const largest = msg.photo[msg.photo.length - 1];
    imageUrl = `tg_file:${largest.file_id}`;
  }

  const hashInput = (text.substring(0, 100)).toLowerCase().replace(/\s+/g, '');
  const content_hash = crypto.createHash('sha256').update(hashInput).digest('hex');

  rows.push({
    source_name: 'telegram',
    source_url: null,
    content_hash,
    raw_title: text.substring(0, 200),
    raw_body: text.substring(0, 5000),
    raw_image_url: imageUrl,
    language: 'en',
    status: 'pending'
  });
}

return [{ json: { rows, max_update_id: maxUpdateId, count: rows.length } }];

const input = $input.first().json;
const rows = input.rows || [];
return rows.map(r => ({ json: r }));

const maxUpdateId = $('Extract Messages + Build Rows').first().json.max_update_id;
const count = $('Extract Messages + Build Rows').first().json.count;
return [{ json: { max_update_id: maxUpdateId, new_offset: maxUpdateId + 1, inserted_count: count } }];

return [{
  json: {
    message: 'Telegram poll complete',
    inserted: $input.first().json.inserted_count,
    timestamp: new Date().toISOString()
  }
}];
